package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.Mockito.mock;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n",
                null, null, false, true);

        // When
        boolean isCommentMarkerSet = invokeIsCommentMarkerSet(csvFormat);

        // Then
        assertTrue(isCommentMarkerSet);

        // Additional Test for when commentMarker is null
        csvFormat = new CSVFormat(',', '"', null, null, '\\', true, false, "\r\n",
                null, null, false, true);

        isCommentMarkerSet = invokeIsCommentMarkerSet(csvFormat);

        assertFalse(isCommentMarkerSet);
    }

    private boolean invokeIsCommentMarkerSet(CSVFormat csvFormat) throws Exception {
        return (boolean) CSVFormat.class.getDeclaredMethod("isCommentMarkerSet").invoke(csvFormat);
    }
}
